Steps:
[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP setup_prod]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 1 filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3 price.USD:(0 TO) inStock_variations:true") { items { id } } }
[GQL-EXEC setup_prod]
[GQL-CAPTURE setup_prod.data.products.items.0.id → PRODUCT_ID]
[GQL-OP add_item]
  mutation {
    addItem(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      cartName: "AGENT-TEST-ORDER-013"
      productId: "{{PRODUCT_ID}}" quantity: 1
    }) { id }
  }
[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.id → CART_ID]
[GQL-OP set_shipment]
  mutation {
    addOrUpdateCartShipment(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      cartName: "AGENT-TEST-ORDER-013"
      shipment: {
        shipmentMethodCode: "FixedRate" shipmentMethodOption: "Ground" price: 150
        deliveryAddress: { city: "New York" countryCode: "US" countryName: "United States" firstName: "Test" lastName: "User" line1: "123 Test St" postalCode: "10001" regionId: "NY" regionName: "New York" }
      }
    }) { id }
  }
[GQL-EXEC set_shipment]
[GQL-OP set_payment]
  mutation {
    addOrUpdateCartPayment(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      cartName: "AGENT-TEST-ORDER-013"
      payment: { paymentGatewayCode: "DefaultManualPaymentMethod" }
    }) { id }
  }
[GQL-EXEC set_payment]
[GQL-OP create_order]
  mutation { createOrderFromCart(command: { cartId: "{{CART_ID}}" }) { id number status } }
[GQL-EXEC create_order]

