[GQL-OP cart_items_full]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD") {
      items {
        id productId sku name quantity
        listPrice { amount }
        salePrice { amount }
        placedPrice { amount }
        extendedPrice { amount }
        discountAmount { amount }
        taxTotal { amount }
        taxPercentRate
        imageUrl
        productType
        isGift
        selectedForCheckout
        catalogId
        categoryId
      }
    }
  }
[GQL-EXEC cart_items_full]
